=You are an AP (Accounts Payable) assistant for a company using SAP B1.

A vendor has sent the following email:

From: {{ $json.from_email }}
Vendor: {{ $json.vendor_name }}
Subject: {{ $json.subject }}
Message: {{ $json.email_body }}

Based on this email, do two things:
1. Identify what the vendor is asking about (payment status, invoice confirmation, payment date, or other)
2. Draft a professional, friendly reply email acknowledging their query and letting them know the AP team will verify the details in SAP B1 and respond within 1 business day.

Format your response as:
QUERY TYPE: [what they're asking]
REPLY EMAIL: [the full draft reply]

parameters.jsCode:
const geminiOutput = $('Message a model').first().json.content.parts[0].text;

const sapFound = $('Code').first().json.found;
const invoiceNumber = $('Code').first().json.invoice_number;
const vendorName = $('Code').first().json.vendor_name;
const amount = $('Code').first().json.amount;
const submittedDate = $('Code').first().json.submitted_date;
const status = $('Code').first().json.status;
const expectedPayment = $('Code').first().json.expected_payment_date;
const paymentTerms = $('Code').first().json.payment_terms;

let finalResponse = '';

if (sapFound) {
  finalResponse = `SAP B1 INVOICE LOOKUP RESULT:
------------------------------
Invoice Number: ${invoiceNumber}
Vendor: ${vendorName}
Amount: $${amount}
Submitted: ${submittedDate}
Status: ${status}
Expected Payment: ${expectedPayment}
Payment Terms: ${paymentTerms}

------------------------------
AI DRAFTED REPLY TO VENDOR:
------------------------------
${geminiOutput}`;
} else {
  finalResponse = `SAP B1 LOOKUP: Invoice not found in system.

AI DRAFTED REPLY TO VENDOR:
------------------------------
${geminiOutput}`;
}

return { final_output: finalResponse };

const invoiceDatabase = [
  {
    invoice_number: "INV-2024-0042",
    vendor_name: "Acme Supplies",
    amount: 4500,
    submitted_date: "2024-06-01",
    status: "Approved",
    expected_payment_date: "2024-07-15",
    payment_terms: "Net 45"
  },
  {
    invoice_number: "INV-2024-0038",
    vendor_name: "Global Parts Co",
    amount: 12750,
    submitted_date: "2024-05-20",
    status: "Pending Approval",
    expected_payment_date: "TBD",
    payment_terms: "Net 30"
  },
  {
    invoice_number: "INV-2024-0051",
    vendor_name: "Tech Solutions Ltd",
    amount: 8200,
    submitted_date: "2024-06-10",
    status: "Payment Scheduled",
    expected_payment_date: "2024-07-05",
    payment_terms: "Net 30"
  }
];

const emailBody = $('Edit Fields').first().json.email_body;
const vendorName = $('Edit Fields').first().json.vendor_name;

const invoiceMatch = emailBody.match(/INV-\d{4}-\d{4}/);
const invoiceNumber = invoiceMatch ? invoiceMatch[0] : null;

const invoiceData = invoiceDatabase.find(inv => 
  inv.invoice_number === invoiceNumber || 
  inv.vendor_name === vendorName
);

if (invoiceData) {
  return { found: true, ...invoiceData };
} else {
  return { 
    found: false, 
    message: "Invoice not found in SAP B1 system" 
  };
}
